query:
mutation {
  suggestFix(
    repo: "test-repo",
    file: "",
    issue: "Unquoted shell variable",
    suggestion: "Replace with proven/SafeCommand"
  ) {
    success
    prNumber
  }
}

mutation {
  submitProofObligation(
    repo: "test-repo",
    claim: "Substitution with SafeCommand preserves behavior",
    context: "Unquoted shell variable"
  ) {
    success
    proofId
  }
}

mutation {
  suggestFix(
    repo: "test-repo",
    file: "scripts/deploy.sh",
    issue: "Unquoted variable",
    suggestion: "Add double quotes"
  ) {
    success
    prNumber
  }
}

mutation {
  reportEcoScore(
    repo: "test-repo",
    score: 0.5,
    details: "Unresolved: Unquoted shell variable (no safe fix available)"
  ) {
    success
  }
}

mutation {
  requestAutoFix(
    repo: "test-repo",
    file: "",
    issue: "Unquoted shell variable",
    fixType: "eliminate",
    confidence: "0.99",
    recipeId: "recipe-shell-quote-vars",
    suggestion: "Quote shell variables"
  ) {
    success
    fixApplied
    fixDecision
  }
}
